scwin.f_FieldClear3 = function () {
  $c.gus.cfInitObjects($p, [ed_fixedAsetNo, ed_fixedAsetNm]);
};

//-------------------------------------------------------------------------
// function name : f_RentloanShapeCdChange
// function desc : 계약형태 변경 시
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_RentloanShapeCdChange = function () {
  let vRentloanShapeCd = lc_rentloanShapeCd.getValue();
  if (vRentloanShapeCd == "01" || vRentloanShapeCd == "02") {
    ChainedISNm.setLabel("경매현황");
  } else if (vRentloanShapeCd == "03" || vRentloanShapeCd == "04") {
    ChainedISNm.setLabel("명도소송현황");
  } else {
    ChainedISNm.setLabel("경매현황");
  }
};
scwin.lc_rentloanShapeCd_onchange = function (info) {
  //계약형태가 임대일 경우
  if (lc_rentloanShapeCd.getValue() == "03") {
    $c.gus.cfDisableObjects($p, [btn_loanCtrtNo, cls_loanCtrtNo, lc_posnClsCd]);
    lc_posnClsCd.setValue("");
    if (ds_out2.getRowCount() > 0) {
      $c.gus.cfEnableObjects($p, [btn_fixedAsetNo]);
    }
    gr_out2.setColumnVisible("fixedAsetNo", true);
    if (ds_out2.getRowCount() > 0) {
      $c.gus.cfDisableObjects($p, [ed_regAreaM2, ed_regAreaPy]);
    }
    //여객이고 임대/전대인 경우
    if (scwin.uppermostBizDomCd == "200") {
      tr_for200.show("table-row");
    } else {
      tr_for200.hide();
    }
  }
  //계약형태가 전대일 경우
  else if (lc_rentloanShapeCd.getValue() == "04") {
    $c.gus.cfEnableObjects($p, [btn_loanCtrtNo, cls_loanCtrtNo]);
    $c.gus.cfDisableObjects($p, [btn_fixedAsetNo]);
    ed_fixedAsetNo.setValue("");
    ed_fixedAsetNm.setValue("");
    gr_out2.setColumnVisible("fixedAsetNo", true);
    if (ds_out2.getRowCount() > 0) {
      $c.gus.cfEnableObjects($p, [ed_regAreaM2, ed_regAreaPy]);
    }

    //여객이고 임대/전대인 경우
    if (scwin.uppermostBizDomCd == "200") {
      tr_for200.show("table-row");
    } else {
      tr_for200.hide();
    }
  } else {
    ed_loanCtrtNo.setValue("");
    $c.gus.cfEnableObjects($p, [lc_posnClsCd]);
    gr_out2.setColumnVisible("fixedAsetNo", false);
    $c.gus.cfDisableObjects($p, [btn_loanCtrtNo, cls_loanCtrtNo]);
    $c.gus.cfDisableObjects($p, [btn_fixedAsetNo]);
    ed_fixedAsetNo.setValue("");
    ed_fixedAsetNm.setValue("");
    if (ds_out2.getRowCount() > 0) {
      $c.gus.cfEnableObjects($p, [ed_regAreaM2, ed_regAreaPy]);
    }
    ed_loanCtrtNo.setValue("");
    ed_fixedAsetNo.setValue("");
    ed_regAreaM2.setValue(0);
    ed_regAreaPy.setValue(0);
  }
  scwin.f_RentloanShapeCdChange();
};
